const ALL_PRODUCTS = [
  ...PRODUCTS_AFTERMARKET.map(p => ({ ...p, categorie: "Aftermarket France" })),
  ...PRODUCTS_XHORSE.map(p => ({ ...p, categorie: "Xhorse" })),
];

const SEUIL_DEFAULT = 3;
const STOCK_KEY = "mrkey_stock_v1";
const SETUP_KEY = "mrkey_setup_done";

const initStock = () => {
  try {
    const saved = localStorage.getItem(STOCK_KEY);
    if (saved) {
      const parsed = JSON.parse(saved);
      const s = { ...parsed };
      ALL_PRODUCTS.forEach(p => {
        if (!s[p.id]) s[p.id] = { qty: 2, seuil: SEUIL_DEFAULT, historique: [], init: true };
      });
      return s;
    }
  } catch (e) {}
  // Premier lancement : tout à 0, init:true
  const s = {};
  ALL_PRODUCTS.forEach(p => { s[p.id] = { qty: 2, seuil: SEUIL_DEFAULT, historique: [], init: true }; });
  return s;
};

const isFirstLaunch = () => {
  try { return !localStorage.getItem(SETUP_KEY); } catch (e) { return false; }
};

